/// <summary>
/// Extension class for form ITMContainers datasource ITMContainers
/// </summary>
[ExtensionOf(FormDataSourceStr(ITMContainers, ITMContainers))]
internal final class ETGITMContainersFormDS_Extension
{
}

Method.Source:
/// <summary>
/// disable purchase order design for outbound orders
/// </summary>
/// <returns>int</returns>
public int active()
{
    int ret = next active();

    this.updateDesignPurchaseOrders();

    return ret;
}

/// <summary>
/// disable purchase order details for outbound orders
/// </summary>
public void updateDesignPurchaseOrders()
{
    FormDataSource      formDS          = this;
    ITMContainers       iTMContainers   = formDS.cursor();
    ITMTable            itmTableCurrent;

    if (ITMParameters::find().ETGEnableLandedCostOutboundOrder == NoYes::No)
    {
        element.design().controlName(formControlStr(ITMContainers, ETGManageSalesOrderGroup)).visible(false);
    }

    else
    {
        select firstonly RecId, ETGLandedCostType from itmTableCurrent
        where itmTableCurrent.ShipId == iTMContainers.ShipId;

        if(itmTableCurrent.RecId && itmTableCurrent.ETGLandedCostType == ETGLandedCostType::Outbound)
        {
            element.design().controlName(formControlStr(ITMContainers, ManagePurchaseOrderGroup)).visible(false);
        }

        if(itmTableCurrent.RecId && itmTableCurrent.ETGLandedCostType == ETGLandedCostType::Inbound)
        {
            element.design().controlName(formControlStr(ITMContainers, ETGManageSalesOrderGroup)).visible(false);
        }
    }

}
